sql:
SELECT *
FROM user_actions
WHERE LOWER(action) = 'viewed' AND action_duration > 300;

external_knowledge:
- "user_id" refers to the unique identifier for each user;
- "action" describes the type of activity performed by the user;
- "action_duration" is the time in seconds that the user spent on the action.

sql:
SELECT user_id, action, action_duration 
FROM user_actions 
ORDER BY action_duration DESC;

